  const q = (ev.query.get("q") ?? "").trim();
  if (!q) return { q: "", ran: false, total: 0, results: [] };
  const { searchDocuments } = await import("~/server/db");
  try {
    return { q, ran: true, ...searchDocuments(q) };
  } catch {
    return { q, ran: true, total: 0, results: [] };
