/**
 * Server-only SQLite + FTS5 module.
 *
 * IMPORTANT: This file imports `better-sqlite3` and `node:*` built-ins, so it
 * must only ever be imported from server-only boundaries (e.g. `routeLoader$`).
 * Never import it from a component that can render on the client.
 */
import Database from "better-sqlite3";
import { mkdirSync } from "node:fs";
import { join } from "node:path";

export interface SearchResult {
  title: string;
  snippet: string;
}

export interface SearchResponse {
  total: number;
  results: SearchResult[];
}

const DATA_DIR = join(process.cwd(), "data");
const DB_PATH = join(DATA_DIR, "search.db");

// The 8 seed documents required by the task.
const SEED_DOCUMENTS: Array<{ title: string; body: string }> = [
  {
    title: "Introduction to SQLite",
    body: "SQLite is a lightweight embedded database engine used in many applications.",
  },
  {
    title: "Full Text Search with FTS5",
    body: "The FTS5 extension enables fast full text search over documents using an inverted index.",
  },
  {
    title: "Getting Started with Qwik",
    body: "Qwik is a resumable web framework that delivers instant loading web applications.",
  },
  {
    title: "Reactive State in Qwik",
    body: "Use signals and stores to manage reactive state inside Qwik components.",
  },
  {
    title: "Building REST APIs",
    body: "Design clean REST endpoints to serve JSON data to client applications.",
  },
  {
    title: "Database Indexing Basics",
    body: "Indexes speed up query performance in relational databases like SQLite and Postgres.",
  },
  {
    title: "Server Side Rendering",
    body: "Server side rendering improves performance and search engine visibility for web applications.",
  },
  {
    title: "Web Performance Tips",
    body: "Reduce JavaScript to improve web performance and loading speed for users.",
  },
];

let db: Database.Database | null = null;

function getDb(): Database.Database {
  if (db) return db;
  mkdirSync(DATA_DIR, { recursive: true });
  const connection = new Database(DB_PATH);
  connection.pragma("journal_mode = WAL");

  // Create the FTS5 virtual table (idempotent).
  connection.exec(
    "CREATE VIRTUAL TABLE IF NOT EXISTS documents USING fts5(title, body);",
  );

  // Idempotent seeding: ensure exactly the 8 seed documents are present.
  const countRow = connection
    .prepare("SELECT count(*) AS c FROM documents")
    .get() as { c: number };

  if (countRow.c !== SEED_DOCUMENTS.length) {
    const wipe = connection.prepare("DELETE FROM documents");
    const insert = connection.prepare(
      "INSERT INTO documents (title, body) VALUES (?, ?)",
    );
    const seed = connection.transaction(() => {
      wipe.run();
      for (const doc of SEED_DOCUMENTS) {
        insert.run(doc.title, doc.body);
      }
    });
    seed();
  }

  db = connection;
  return connection;
}

/**
 * Run an FTS5 MATCH query against the documents corpus, returning results
 * ranked by BM25 relevance (best match first) with highlighted snippets.
 */
export function searchDocuments(query: string): SearchResponse {
  const connection = getDb();

  // snippet(table, column-index, start-marker, end-marker, ellipsis, token-count)
  // column index 1 == the `body` column. Matched terms are wrapped in <mark>.
  const stmt = connection.prepare(`
    SELECT
      documents.title AS title,
      snippet(documents, 1, '<mark>', '</mark>', '…', 12) AS snippet,
      bm25(documents) AS rank
    FROM documents
    WHERE documents MATCH ?
    ORDER BY rank
    LIMIT 50;
  `);

  let rows: Array<{ title: string; snippet: string }> = [];
  try {
    rows = stmt.all(query) as Array<{ title: string; snippet: string }>;
  } catch {
    // Invalid FTS5 query syntax (e.g. unbalanced quotes) -> no results.
    rows = [];
  }

  return {
    total: rows.length,
    results: rows.map((r) => ({ title: r.title, snippet: r.snippet })),
  };
}

import {
  component$,
  useSignal,
  useTask$,
  $,
  type QRL,
} from "@builder.io/qwik";
import {
  routeLoader$,
  useNavigate,
  useLocation,
  type DocumentHead,
} from "@builder.io/qwik-city";

export const useSearch = routeLoader$(async (requestEvent) => {
  const raw = requestEvent.query.get("q");
  const q = (raw ?? "").trim();

  // Empty-query state: do not run a search.
  if (!q) {
    return { q: "", ran: false, total: 0, results: [] as Result[] };
  }

  const { searchDocuments } = await import("~/server/db");
  const { total, results } = searchDocuments(q);
  return { q, ran: true, total, results };
});

interface Result {
  title: string;
  snippet: string;
}

export default component$(() => {
  const data = useSearch();
  const loc = useLocation();
  const nav = useNavigate();

  // The controlled input value.
  const inputValue = useSignal(data.value?.q ?? "");
  // Debounce timer handle (client-only).
  const timer = useSignal<ReturnType<typeof setTimeout> | undefined>(undefined);

  // Keep the input in sync with the URL `q` param (e.g. on initial load, back/forward).
  useTask$(({ track }) => {
    const urlQ = track(() => loc.url.searchParams.get("q") ?? "");
    if (urlQ.trim() !== inputValue.value.trim()) {
      inputValue.value = urlQ;
    }
  });

  // Debounced input handler: update the `q` URL query param as the user types.
  const onInput = $((e: Event) => {
    const target = e.target as HTMLInputElement;
    inputValue.value = target.value;

    if (timer.value) {
      clearTimeout(timer.value);
    }
    timer.value = setTimeout(() => {
      const value = target.value.trim();
      const target_url = value
        ? `/?q=${encodeURIComponent(value)}`
        : "/";
      nav(target_url, { type: "replaceState" });
    }, 300) as unknown as ReturnType<typeof setTimeout>;
  });

  return (
    <main class="search-page">
      <h1>Full-Text Document Search</h1>
      <p class="subtitle">
        Search the document corpus using SQLite FTS5 full-text search.
      </p>

      <form
        preventdefault:submit
        role="search"
      >
        <input
          type="search"
          name="q"
          aria-label="Search documents"
          placeholder="Enter a search term…"
          autoComplete="off"
          value={inputValue.value}
          onInput$={onInput as QRL<(e: Event) => void>}
          autofocus
        />
      </form>

      {!data.value.ran && (
        <p class="state empty-state">Enter a search term to begin.</p>
      )}

      {data.value.ran && (
        <>
          <p class="result-count">{data.value.total} results</p>

          {data.value.total === 0 ? (
            <p class="state no-results">
              No results found for &ldquo;{data.value.q}&rdquo;.
            </p>
          ) : (
            <ol class="results">
              {data.value.results.map((result, index) => (
                <li class="result" key={result.title}>
                  <span class="rank">{index + 1}</span>
                  <div class="result-body">
                    <h2 class="result-title">{result.title}</h2>
                    <p
                      class="snippet"
                      dangerouslySetInnerHTML={result.snippet}
                    />
                  </div>
                </li>
              ))}
            </ol>
          )}
        </>
      )}
    </main>
  );
});

export const head: DocumentHead = {
  title: "Full-Text Document Search",
  meta: [
    {
      name: "description",
      content: "Server-rendered full-text search powered by SQLite FTS5.",
    },
  ],
};

:root {
  --bg: #0f172a;
  --panel: #1e293b;
  --text: #e2e8f0;
  --muted: #94a3b8;
  --accent: #38bdf8;
  --mark-bg: #fde68a;
  --mark-text: #78350f;
  --border: #334155;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto,
    Helvetica, Arial, sans-serif;
  line-height: 1.5;
}

.search-page {
  max-width: 760px;
  margin: 0 auto;
  padding: 2.5rem 1.25rem 4rem;
}

.search-page h1 {
  font-size: 1.9rem;
  margin: 0 0 0.25rem;
}

.subtitle {
  color: var(--muted);
  margin: 0 0 1.75rem;
}

form[role="search"] input[type="search"] {
  width: 100%;
  padding: 0.85rem 1rem;
  font-size: 1.05rem;
  border: 1px solid var(--border);
  border-radius: 0.6rem;
  background: var(--panel);
  color: var(--text);
  outline: none;
}

form[role="search"] input[type="search"]:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(56, 189, 248, 0.25);
}

.result-count {
  margin: 1.75rem 0 1rem;
  font-weight: 600;
  color: var(--text);
}

.state {
  color: var(--muted);
